  {
    json: {
      'Snapshot ID': `agent_whatsapp_${today}`,
      'Snapshot Date': today,
      'Agent ID': 'agent_whatsapp',
      'Messages Handled': 0,
      'Success Rate': 0,
    }
  },
];

return snapshots;

