const airtableRecord = $('Create Ticket').first().json;
return {
  json: {
    ticket_id: airtableRecord.fields ? airtableRecord.fields['Ticket ID'] : 'unknown',
    record_id: airtableRecord.id || '',
    email: ticketData.ticket.email,
    subject: ticketData.ticket.subject,
    body: ticketData.ticket.body,
    category: ticketData.classification.category,
    department: ticketData.classification.department,
    suggested_resolution: ticketData.classification.suggested_resolution,
  }
};

// Calculate SLA status for open tickets
const tickets = $('Read Open Tickets').first().json;
const slaConfig = $('Read SLA Config').first().json;

const ticketList = Array.isArray(tickets) ? tickets : (tickets.records || [tickets]);
const slaList = Array.isArray(slaConfig) ? slaConfig : (slaConfig.records || [slaConfig]);

// Build SLA lookup
const slaLookup = {};
for (const sla of slaList) {
  const fields = sla.fields || sla;
  const priority = fields['Priority'] || fields.priority;
  slaLookup[priority] = {
    response_hours: fields['Response Time Hours'] || 4,
    resolution_hours: fields['Resolution Time Hours'] || 72,
  };
}

const now = new Date();
const breached = [];
const warning = [];

for (const ticket of ticketList) {
  const fields = ticket.fields || ticket;
  const priority = fields['Priority'] || 'P3';
  const createdAt = new Date(fields['Created At'] || now);
  const slaDueAt = fields['SLA Due At'] ? new Date(fields['SLA Due At']) : null;

  const sla = slaLookup[priority] || { response_hours: 8, resolution_hours: 72 };
  const dueTime = slaDueAt || new Date(createdAt.getTime() + sla.resolution_hours * 60 * 60 * 1000);
  const hoursRemaining = (dueTime - now) / (1000 * 60 * 60);
  const totalHours = sla.resolution_hours;
  const percentUsed = Math.round(((totalHours - hoursRemaining) / totalHours) * 100);

  const record = {
    ticket_id: fields['Ticket ID'] || ticket.id || 'unknown',
    subject: fields['Subject'] || '',
    priority: priority,
    client_email: fields['Client Email'] || '',
    status: fields['Status'] || 'Open',
    created_at: createdAt.toISOString(),
    sla_due: dueTime.toISOString(),
    hours_remaining: Math.round(hoursRemaining * 10) / 10,
    percent_used: percentUsed,
  };

  if (hoursRemaining <= 0) {
    breached.push(record);
  } else if (percentUsed >= 75) {
    warning.push(record);
  }
}

return {
  json: {
    breached: breached,
    warning: warning,
    summary: {
      total_checked: ticketList.length,
      breached_count: breached.length,
      warning_count: warning.length,
      checked_at: now.toISOString(),
    }
  }
};

// Parse AI auto-resolution response
const input = $input.first().json;
const ticketData = $('Execute Workflow Trigger').first().json;

let resolution;
try {
  const content = input.choices[0].message.content;
  const cleaned = content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  const jsonMatch = cleaned.match(/\{[\s\S]*\}/);
  resolution = JSON.parse(jsonMatch ? jsonMatch[0] : cleaned);
} catch(e) {
  resolution = {
    response_html: '<p>We received your support request and are looking into it. A team member will respond shortly.</p>',
    confidence: 0.0,
    kb_articles_used: [],
    needs_human_review: true,
    resolution_type: 'escalation_needed',
  };
}

return {
  json: {
    ticket_id: ticketData.ticket_id,
    record_id: ticketData.record_id,
    email: ticketData.email,
    subject: ticketData.subject,
    resolution: resolution,
    auto_resolved: resolution.confidence > 0.85 && !resolution.needs_human_review,
  }
};

// Group resolved tickets by category and find patterns
const tickets = $input.all();
const groups = {};

for (const item of tickets) {
  const fields = item.json.fields || item.json;
  const category = fields['Category'] || fields.category || 'General';
  const subject = fields['Subject'] || fields.subject || '';
  const resolution = fields['Resolution Notes'] || fields.resolution_notes || '';
  const aiSummary = fields['AI Summary'] || fields.ai_summary || '';

  if (!groups[category]) {
    groups[category] = [];
  }
  groups[category].push({
    ticket_id: fields['Ticket ID'] || item.json.id || 'unknown',
    subject: subject,
    ai_summary: aiSummary,
    resolution: resolution,
  });
}

// Find patterns (categories with 2+ tickets)
const patterns = [];
for (const [category, ticketList] of Object.entries(groups)) {
  if (ticketList.length >= 2) {
    patterns.push({
      category: category,
      count: ticketList.length,
      tickets: ticketList,
    });
  }
}

return {
  json: {
    patterns: patterns,
    total_resolved: tickets.length,
    categories_with_patterns: patterns.length,
  }
};

