// Match WhatsApp contacts against Supabase clients via HTTP response
const contacts = $('Read WhatsApp Contacts').all();
const supabaseData = $('Fetch Supabase Clients').first().json;

const clients = Array.isArray(supabaseData) ? supabaseData : (supabaseData.data || []);
const clientMap = {};
for (const c of clients) {
  if (c.phone) clientMap[c.phone.replace(/\D/g, '')] = c;
  if (c.email) clientMap[c.email.toLowerCase()] = c;
}

const results = [];
for (const item of contacts) {
  const d = item.json;
  const phone = (d.Phone || d.phone || '').replace(/\D/g, '');
  const email = (d.Email || d.email || '').toLowerCase();
  const match = clientMap[phone] || clientMap[email] || null;

  results.push({
    json: {
      contactId: d.id || d['Record ID'] || d.airtable_id,
      phone: d.Phone || d.phone,
      name: d.Name || d.name,
      email: d.Email || d.email,
      supabaseMatch: !!match,
      supabaseClientId: match ? match.id : null,
      supabaseStatus: match ? (match.status || 'active') : null,
    }
  });
}

if (results.length === 0) {
  results.push({ json: { message: 'No contacts to sync', matchCount: 0 } });
}

return results;

// Match contacts against SEO Leads Airtable search results
const contacts = $('Match Supabase Clients').all();
const seoLeads = $('Search SEO Leads').all();

const leadMap = {};
for (const item of seoLeads) {
  const d = item.json;
  const phone = (d.Phone || d.phone || '').replace(/\D/g, '');
  const email = (d.Email || d.email || '').toLowerCase();
  if (phone) leadMap[phone] = d;
  if (email) leadMap[email] = d;
}

let matchCount = 0;
let supabaseMatchCount = 0;
let seoMatchCount = 0;

const results = [];
for (const item of contacts) {
  const d = item.json;
  const phone = (d.phone || '').replace(/\D/g, '');
  const email = (d.email || '').toLowerCase();
  const seoMatch = leadMap[phone] || leadMap[email] || null;

  if (d.supabaseMatch) supabaseMatchCount++;
  if (seoMatch) seoMatchCount++;
  if (d.supabaseMatch || seoMatch) matchCount++;

  results.push({
    json: {
      ...d,
      seoLeadMatch: !!seoMatch,
      seoLeadStatus: seoMatch ? (seoMatch.Status || seoMatch.status) : null,
      syncStatus: d.supabaseMatch || seoMatch ? 'matched' : 'orphan',
    }
  });
}

return results;

// Log sync statistics
const items = $('Update Contact Status').all();
let matched = 0;
let orphan = 0;
let errors = 0;

for (const item of items) {
  const status = item.json.syncStatus || 'unknown';
  if (status === 'matched') matched++;
  else if (status === 'orphan') orphan++;
  else errors++;
}

return {
  json: {
    syncedAt: new Date().toISOString(),
    totalContacts: items.length,
    matched,
    orphan,
    errors,
    summary: `Synced ${items.length} contacts: ${matched} matched, ${orphan} orphan, ${errors} errors`,
  }
};

// Scan incoming message for complaint/urgency keywords and compute urgency score
const input = $input.first().json;
const text = ((input.body || input.message || input.text || '') + '').toLowerCase();

const urgencyKeywords = [
  { word: 'urgent', weight: 0.9 },
  { word: 'broken', weight: 0.7 },
  { word: 'refund', weight: 0.8 },
  { word: 'cancel', weight: 0.8 },
  { word: 'frustrated', weight: 0.7 },
  { word: 'help', weight: 0.4 },
  { word: 'angry', weight: 0.8 },
  { word: 'deadline', weight: 0.7 },
  { word: 'asap', weight: 0.9 },
  { word: 'escalate', weight: 1.0 },
];

let totalWeight = 0;
let matchedKeywords = [];
for (const kw of urgencyKeywords) {
  if (text.includes(kw.word)) {
    totalWeight += kw.weight;
    matchedKeywords.push(kw.word);
  }
}

// Normalize to 0-1 range (cap at 1.0)
const urgencyScore = Math.min(totalWeight / 2.0, 1.0);

return {
  json: {
    ...input,
    urgencyScore: Math.round(urgencyScore * 100) / 100,
    matchedKeywords,
    keywordCount: matchedKeywords.length,
    isUrgent: urgencyScore > 0.7,
    scannedAt: new Date().toISOString(),
  }
};

